package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

public class CSVFormatTest {

    @Test
    public void testWithIgnoreHeaderCase() throws NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        boolean ignoreHeaderCase = true;

        // When
        Method method = CSVFormat.class.getDeclaredMethod("withIgnoreHeaderCase", boolean.class);
        method.setAccessible(true);
        CSVFormat result = (CSVFormat) method.invoke(csvFormat, ignoreHeaderCase);

        // Then
        assertNotNull(result);
        assertEquals(ignoreHeaderCase, result.getIgnoreHeaderCase());
    }
}
